import React, { useEffect, useRef, useState } from 'react';
import ReactDOM from 'react-dom';
import styled from 'styled-components';

const CursorWrapper = styled.div`
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  z-index: 2147483647; /* Maximum z-index value */
  isolation: isolate;
`;

const Cursor = styled.div`
  position: absolute;
  width: 25px;
  height: 25px;
  transform: translate(-12.5px, -12.5px);
  pointer-events: none;
  
  svg {
    width: 100%;
    height: 100%;
    filter: drop-shadow(0 0 3px rgba(185, 116, 255, 0.8));
    transition: transform 0.2s ease-out, filter 0.2s ease-out;
    
    path {
      fill: #b974ff;
      stroke: #FFFFFF;
      stroke-width: 0.5;
      transition: fill 0.2s ease-out, stroke-width 0.2s ease-out, stroke 0.2s ease-out;
    }
  }
  
  &.hovering {
    svg {
      transform: scale(1.15) rotate(-10deg);
      filter: drop-shadow(0 0 6px rgba(185, 116, 255, 1));
      transition: none;
      
      path {
        fill: #9945ff;
        stroke: #FFFFFF;
        stroke-width: 1;
      }
    }
  }
  
  &.button-hovering {
    svg {
      transform: scale(1.25) rotate(-15deg);
      filter: drop-shadow(0 0 10px rgba(153, 69, 255, 1)) drop-shadow(0 0 20px rgba(153, 69, 255, 0.5));
      transition: transform 0.15s ease-out, filter 0.15s ease-out;
      
      path {
        fill: #9945ff;
        stroke: #FFFFFF;
        stroke-width: 1.5;
      }
    }
  }
`;

const TrailDot = styled.div`
  position: absolute;
  width: 4px;
  height: 4px;
  background: var(--color-neon-purple);
  border-radius: 50%;
  pointer-events: none;
  will-change: transform, opacity;
  box-shadow: 0 0 6px var(--color-neon-purple);
`;

const CustomCursor = () => {
  const cursorRef = useRef(null);
  const requestRef = useRef(null);
  const previousTimeRef = useRef(null);
  const [portalContainer, setPortalContainer] = useState(null);
  
  const mousePos = useRef({ x: 0, y: 0 });
  const currentPos = useRef({ x: 0, y: 0 });
  const isHovering = useRef(false);
  
  // Trail system
  const trailElements = useRef([]);
  const trailPositions = useRef([]);
  const TRAIL_LENGTH = 20;
  
  useEffect(() => {
    // Create portal container with maximum z-index
    const container = document.createElement('div');
    container.id = 'custom-cursor-portal';
    container.style.cssText = `
      position: fixed !important;
      top: 0 !important;
      left: 0 !important;
      width: 100vw !important;
      height: 100vh !important;
      pointer-events: none !important;
      z-index: 2147483647 !important;
      isolation: isolate !important;
    `;
    
    // Add container as the very last element once
    setTimeout(() => {
      document.body.appendChild(container);
    }, 0);
    setPortalContainer(container);
    
    return () => {
      if (container && document.body.contains(container)) {
        document.body.removeChild(container);
      }
    };
  }, []);
  
  useEffect(() => {
    if (!portalContainer) return;
    
    // Check for touch device or reduced motion
    const isTouchDevice = 'ontouchstart' in window;
    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    
    if (isTouchDevice || prefersReducedMotion) {
      return;
    }
    
    // Hide default cursor globally with highest specificity
    const styleSheet = document.createElement('style');
    styleSheet.textContent = `
      *, *::before, *::after {
        cursor: none !important;
      }
      html, body {
        cursor: none !important;
      }
      button, a, input, textarea, select, [role="button"], 
      .scroll-to-top-fixed-button, .floating-contact-island {
        cursor: none !important;
      }
    `;
    document.head.appendChild(styleSheet);
    
    // Mouse move handler
    const handleMouseMove = (e) => {
      mousePos.current = { x: e.clientX, y: e.clientY };
      currentPos.current = { x: e.clientX, y: e.clientY };
      
      // Update cursor position immediately
      if (cursorRef.current) {
        cursorRef.current.style.transform = `translate3d(${e.clientX}px, ${e.clientY}px, 0) translate(-12.5px, -12.5px)`;
      }
    };
    
    // Hover handlers
    const handleMouseEnter = (e) => {
      isHovering.current = true;
      if (cursorRef.current) {
        // Check if hovering over a button or floating contact/scroll button
        const target = e.target;
        const isButton = target.tagName === 'BUTTON' || 
                        target.closest('button') || 
                        target.closest('.scroll-to-top-fixed-button') ||
                        target.closest('.floating-contact-island');
        
        cursorRef.current.classList.remove('hovering', 'button-hovering');
        
        if (isButton) {
          cursorRef.current.classList.add('button-hovering');
        } else {
          cursorRef.current.classList.add('hovering');
        }
      }
    };
    
    const handleMouseLeave = () => {
      isHovering.current = false;
      if (cursorRef.current) {
        cursorRef.current.classList.remove('hovering');
        cursorRef.current.classList.remove('button-hovering');
      }
    };
    
    // Animation loop using RAF (only for trail)
    const updateCursor = (time) => {
      if (previousTimeRef.current !== undefined) {
        // Initialize trail if needed
        if (trailPositions.current.length === 0) {
          for (let i = 0; i < TRAIL_LENGTH; i++) {
            trailPositions.current.push({ x: currentPos.current.x, y: currentPos.current.y });
          }
        }
        
        // Simple trail following with lag
        for (let i = TRAIL_LENGTH - 1; i > 0; i--) {
          const target = trailPositions.current[i - 1];
          const current = trailPositions.current[i];
          
          // Simple interpolation - more lag for distant dots
          const lagFactor = 0.5 - (i / TRAIL_LENGTH) * 0.3;
          
          current.x += (target.x - current.x) * lagFactor;
          current.y += (target.y - current.y) * lagFactor;
        }
        
        // First trail position follows cursor
        trailPositions.current[0].x += (currentPos.current.x - trailPositions.current[0].x) * 0.8;
        trailPositions.current[0].y += (currentPos.current.y - trailPositions.current[0].y) * 0.8;
        
        // Animate trail elements
        trailElements.current.forEach((element, index) => {
          if (element && trailPositions.current[index]) {
            const { x, y } = trailPositions.current[index];
            const progress = index / TRAIL_LENGTH;
            const scale = 1 - progress * 0.7;
            const opacity = 1 - progress * 0.95;
            
            element.style.transform = `translate3d(${x - 2}px, ${y - 2}px, 0) scale(${scale})`;
            element.style.opacity = opacity;
          }
        });
      }
      
      previousTimeRef.current = time;
      requestRef.current = requestAnimationFrame(updateCursor);
    };
    
    // Event listeners
    window.addEventListener('mousemove', handleMouseMove, { passive: true });
    
    // Add hover listeners to interactive elements
    const addHoverListeners = () => {
      const elements = document.querySelectorAll('a, button, input, textarea, select, [role="button"], .scroll-to-top-fixed-button, .floating-contact-island');
      elements.forEach(el => {
        el.addEventListener('mouseenter', handleMouseEnter);
        el.addEventListener('mouseleave', handleMouseLeave);
      });
    };
    
    // Initial setup
    addHoverListeners();
    
    // Watch for DOM changes - ONLY for adding hover listeners
    const observer = new MutationObserver(() => {
      addHoverListeners();
    });
    
    observer.observe(document.body, {
      childList: true,
      subtree: true
    });
    
    // Start animation
    requestRef.current = requestAnimationFrame(updateCursor);
    
    // Cleanup
    return () => {
      if (styleSheet && styleSheet.parentNode) {
        styleSheet.parentNode.removeChild(styleSheet);
      }
      
      window.removeEventListener('mousemove', handleMouseMove);
      
      const elements = document.querySelectorAll('a, button, input, textarea, select, [role="button"], .scroll-to-top-fixed-button, .floating-contact-island');
      elements.forEach(el => {
        el.removeEventListener('mouseenter', handleMouseEnter);
        el.removeEventListener('mouseleave', handleMouseLeave);
      });
      
      observer.disconnect();
      
      if (requestRef.current) {
        cancelAnimationFrame(requestRef.current);
      }
    };
  }, [portalContainer]);
  
  if (!portalContainer) return null;
  
  return ReactDOM.createPortal(
    <CursorWrapper>
      {/* Trail dots */}
      {[...Array(TRAIL_LENGTH)].map((_, i) => (
        <TrailDot
          key={i}
          ref={el => trailElements.current[i] = el}
        />
      ))}
      
      {/* Main cursor */}
      <Cursor ref={cursorRef}>
        <svg xmlns="http://www.w3.org/2000/svg" width="33" height="33" viewBox="0 0 24 24">
          <path d="M5.5 3.21V20.8c0 .45.54.67.85.35l4.86-4.86a.5.5 0 0 1 .35-.15h6.87a.5.5 0 0 0 .35-.85L6.35 2.85a.5.5 0 0 0-.85.35Z" />
        </svg>
      </Cursor>
    </CursorWrapper>,
    portalContainer
  );
};

export default CustomCursor;