import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

// Initialize scroll-triggered animations with smooth effects
export const initScrollAnimations = () => {
  // Smooth fade-in animations
  ScrollTrigger.batch('.fade-in', {
    start: 'top 85%',
    end: 'bottom 15%',
    onEnter: batch => gsap.to(batch, {
      opacity: 1,
      y: 0,
      duration: 1.2,
      ease: 'power2.out',
      stagger: 0.1,
      overwrite: 'auto'
    }),
    onLeave: batch => gsap.set(batch, {
      opacity: 0,
      y: 30,
      overwrite: 'auto'
    }),
    onEnterBack: batch => gsap.to(batch, {
      opacity: 1,
      y: 0,
      duration: 0.8,
      ease: 'power2.out',
      stagger: 0.08,
      overwrite: 'auto'
    }),
    onLeaveBack: batch => gsap.set(batch, {
      opacity: 0,
      y: 30,
      overwrite: 'auto'
    })
  });
  
  // Set initial state for fade-in elements
  gsap.set('.fade-in', { opacity: 0, y: 30 });
  
  // Parallax effects for elements with data-speed
  const parallaxElements = gsap.utils.toArray('[data-speed]');
  parallaxElements.forEach(element => {
    const speed = parseFloat(element.dataset.speed) || 0.5;
    
    ScrollTrigger.create({
      trigger: element,
      start: 'top bottom',
      end: 'bottom top',
      scrub: 1, // Smooth scrubbing
      onUpdate: self => {
        const yPos = self.progress * 100 * (1 - speed);
        gsap.set(element, { 
          yPercent: -yPos,
          force3D: true // Hardware acceleration
        });
      }
    });
  });
  
  // Scale animations on scroll
  const scaleElements = gsap.utils.toArray('[data-scale]');
  scaleElements.forEach(element => {
    gsap.fromTo(element, 
      { scale: 0.8, opacity: 0 },
      {
        scale: 1,
        opacity: 1,
        duration: 1,
        scrollTrigger: {
          trigger: element,
          start: 'top 80%',
          end: 'top 50%',
          scrub: 1
        }
      }
    );
  });
};

// Debounced refresh for responsive changes
let refreshTimeout;
export const debouncedRefresh = () => {
  clearTimeout(refreshTimeout);
  refreshTimeout = setTimeout(() => {
    ScrollTrigger.refresh();
  }, 300);
};

// Add resize listener
window.addEventListener('resize', debouncedRefresh);