import React, { useState, useEffect } from 'react';
import ReactDOM from 'react-dom';
import { motion, AnimatePresence } from 'framer-motion';

const ScrollToTop = () => {
  const [isVisible, setIsVisible] = useState(false);
  const [scrollProgress, setScrollProgress] = useState(0);
  const [portalContainer, setPortalContainer] = useState(null);
  
  useEffect(() => {
    // Create portal container
    const container = document.createElement('div');
    container.id = 'scroll-to-top-portal';
    container.className = 'scroll-to-top-fixed-button';
    container.style.cssText = `
      position: fixed !important;
      top: 0 !important;
      left: 0 !important;
      width: 100vw !important;
      height: 100vh !important;
      pointer-events: none !important;
      z-index: 9999 !important;
      transform: none !important;
    `;
    document.body.appendChild(container);
    setPortalContainer(container);
    
    return () => {
      if (container && document.body.contains(container)) {
        document.body.removeChild(container);
      }
    };
  }, []);
  
  useEffect(() => {
    const toggleVisibility = () => {
      const scrolled = window.scrollY || window.pageYOffset || document.documentElement.scrollTop || 0;
      const totalHeight = document.documentElement.scrollHeight - window.innerHeight;
      const progress = Math.min((scrolled / totalHeight) * 100, 100);
      
      setScrollProgress(progress);
      setIsVisible(scrolled > 300);
    };
    
    // Listen to native scroll
    window.addEventListener('scroll', toggleVisibility, { passive: true });
    
    // Initial check
    toggleVisibility();
    
    return () => {
      window.removeEventListener('scroll', toggleVisibility);
    };
  }, []);
  
  const scrollToTop = () => {
    // Simple smooth scroll to top
    window.scrollTo({
      top: 0,
      behavior: 'smooth'
    });
  };
  
  if (!portalContainer) return null;
  
  return ReactDOM.createPortal(
    <AnimatePresence>
      {isVisible && (
        <motion.button
          onClick={scrollToTop}
          aria-label="Scroll to top"
          className="scroll-to-top-fixed-button"
          style={{
            position: 'fixed',
            bottom: window.innerWidth <= 768 ? '1.5rem' : '3rem',
            right: window.innerWidth <= 768 ? '1.5rem' : '3rem',
            width: window.innerWidth <= 768 ? '48px' : '60px',
            height: window.innerWidth <= 768 ? '48px' : '60px',
            borderRadius: '50%',
            border: 'none',
            background: 'linear-gradient(135deg, #4a0080 0%, #9945ff 100%)',
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            boxShadow: '0 0 20px rgba(153, 69, 255, 0.5)',
            zIndex: 9999,
            pointerEvents: 'auto',
            overflow: 'hidden',
            transform: 'none'
          }}
          initial={{ opacity: 0, scale: 0.5 }}
          animate={{ opacity: 1, scale: 1 }}
          exit={{ opacity: 0, scale: 0.5 }}
          whileHover={{ 
            scale: 1.1,
            boxShadow: '0 0 30px rgba(153, 69, 255, 0.8)'
          }}
          whileTap={{ scale: 0.95 }}
          transition={{ duration: 0.3 }}
        >
          {/* Progress Ring */}
          <svg 
            style={{
              position: 'absolute',
              top: 0,
              left: 0,
              width: '100%',
              height: '100%',
              transform: 'rotate(-90deg)'
            }}
          >
            <circle
              cx={window.innerWidth <= 768 ? "24" : "30"}
              cy={window.innerWidth <= 768 ? "24" : "30"}
              r={window.innerWidth <= 768 ? "20" : "26"}
              fill="none"
              stroke="rgba(255, 255, 255, 0.3)"
              strokeWidth="2"
              strokeDasharray={`${2 * Math.PI * (window.innerWidth <= 768 ? 20 : 26)}`}
              strokeDashoffset={`${2 * Math.PI * (window.innerWidth <= 768 ? 20 : 26) - (scrollProgress / 100) * 2 * Math.PI * (window.innerWidth <= 768 ? 20 : 26)}`}
              style={{ transition: 'stroke-dashoffset 0.3s ease' }}
            />
          </svg>
          
          {/* Arrow Icon */}
          <svg 
            viewBox="0 0 24 24" 
            style={{
              width: '24px',
              height: '24px',
              fill: 'none',
              stroke: '#fff',
              strokeWidth: '2',
              strokeLinecap: 'round',
              strokeLinejoin: 'round',
              zIndex: 1
            }}
          >
            <path d="M7 14l5-5 5 5" />
          </svg>
        </motion.button>
      )}
    </AnimatePresence>,
    portalContainer
  );
};

export default ScrollToTop;