import React, { useEffect, useState, lazy, Suspense } from 'react';
import styled from 'styled-components';
import { motion, AnimatePresence } from 'framer-motion';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { initCSSNativeScroll } from './utils/cssNativeScroll';
import { initScrollAnimations } from './utils/scrollConfig';
import CustomCursor from './components/common/CustomCursor';
import ScrollToTop from './components/common/ScrollToTop';
import FloatingContact from './components/common/FloatingContact';
import LoadingScreen from './components/common/LoadingScreen';
import Navigation from './components/Navigation/Navigation';
import Hero from './components/Hero/Hero';
import useKeyboardNavigation from './hooks/useKeyboardNavigation';
import './styles/global.css';

// Lazy load heavy components
const PerformanceMonitor = lazy(() => import('./components/common/PerformanceMonitor'));
const About = lazy(() => import('./components/About/About'));
const Skills = lazy(() => import('./components/Skills/Skills'));
const Services = lazy(() => import('./components/Services/Services'));
const Clients = lazy(() => import('./components/Clients/Clients'));
const Footer = lazy(() => import('./components/Footer/Footer'));

// Register GSAP plugins
gsap.registerPlugin(ScrollTrigger);

const AppContainer = styled.div`
  position: relative;
  width: 100%;
  background: var(--color-deep-purple);
  /* Prevent margin collapse */
  padding-top: 0.1px;
`;

const MainContent = styled.main`
  position: relative;
  z-index: 1;
  /* Prevent margin collapse between sections */
  display: flex;
  flex-direction: column;
`;

const SectionWrapper = styled.section`
  position: relative;
  width: 100%;
  min-height: 100vh;
  z-index: 1;
  background: var(--color-deep-purple);
  /* Prevent margin collapse */
  padding-top: 0.1px;
  padding-bottom: 0.1px;
`;

const LoadingFallback = styled.div`
  min-height: 400px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-text-secondary);
`;

const pageVariants = {
  initial: {
    opacity: 0,
  },
  animate: {
    opacity: 1,
    transition: {
      duration: 0.8,
      ease: [0.6, -0.05, 0.01, 0.99],
      staggerChildren: 0.2,
    },
  },
};

const App = () => {
  const [isLoading, setIsLoading] = useState(true);
  const [isTouchDevice, setIsTouchDevice] = useState(false);
  useKeyboardNavigation();
  
  useEffect(() => {
    // Check for touch device
    const checkTouchDevice = () => {
      setIsTouchDevice('ontouchstart' in window || navigator.maxTouchPoints > 0);
    };
    checkTouchDevice();
    
    // Configure ScrollTrigger
    ScrollTrigger.config({
      ignoreMobileResize: true,
      autoRefreshEvents: "visibilitychange,DOMContentLoaded,load"
    });
    
    // Initialize CSS native scrolling with enhanced animations
    // No lag, perfect ScrollTrigger compatibility
    const cleanupScroll = initCSSNativeScroll();
    
    // Initialize scroll animations
    initScrollAnimations();
    
    return () => {
      if (cleanupScroll) cleanupScroll();
    };
  }, []);
  
  useEffect(() => {
    if (!isLoading) {
      // Just refresh ScrollTrigger after content loads
      ScrollTrigger.refresh();
      
      // Delayed refresh to ensure everything is loaded
      const refreshTimer = setTimeout(() => {
        ScrollTrigger.refresh();
      }, 500);
      
      return () => {
        clearTimeout(refreshTimer);
      };
    }
  }, [isLoading]);
  
  return (
    <>
      <LoadingScreen onLoadingComplete={() => setIsLoading(false)} />
      {!isLoading && (
        <>
          <ScrollToTop />
          <FloatingContact />
          <AnimatePresence>
            <AppContainer>
              <Suspense fallback={null}>
                <PerformanceMonitor />
              </Suspense>
              <Navigation />
        
              <MainContent>
                <motion.div
                  variants={pageVariants}
                  initial="initial"
                  animate="animate"
                >
                  <SectionWrapper id="hero">
                    <Hero />
                  </SectionWrapper>
                  
                  <SectionWrapper id="about">
                    <Suspense fallback={<LoadingFallback>Loading...</LoadingFallback>}>
                      <About />
                    </Suspense>
                  </SectionWrapper>
                  
                  <SectionWrapper id="skills">
                    <Suspense fallback={<LoadingFallback>Loading...</LoadingFallback>}>
                      <Skills />
                    </Suspense>
                  </SectionWrapper>
                </motion.div>
                
                {/* Services MUST be outside motion.div for pinning to work! */}
                <Suspense fallback={<LoadingFallback>Loading...</LoadingFallback>}>
                  <Services />
                </Suspense>
                
                <motion.div
                  variants={pageVariants}
                  initial="initial"
                  animate="animate"
                >
                  <SectionWrapper id="clients">
                    <Suspense fallback={<LoadingFallback>Loading...</LoadingFallback>}>
                      <Clients />
                    </Suspense>
                  </SectionWrapper>
                  
                  <Suspense fallback={<LoadingFallback>Loading...</LoadingFallback>}>
                    <Footer />
                  </Suspense>
                </motion.div>
              </MainContent>
            </AppContainer>
          </AnimatePresence>
          {!isTouchDevice && <CustomCursor />}
        </>
      )}
    </>
  );
};

export default App;