import React, { useEffect, useState, useRef, useCallback } from 'react';
import styled, { keyframes } from 'styled-components';
import { motion } from 'framer-motion';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';

const CodeContainer = styled(motion.div)`
  position: relative;
  background: var(--color-dark-surface);
  border: 1px solid rgba(153, 69, 255, 0.3);
  border-radius: var(--radius-xl);
  overflow: hidden;
  backdrop-filter: blur(10px);
  box-shadow: 
    0 20px 40px rgba(0, 0, 0, 0.5),
    inset 0 1px 0 rgba(153, 69, 255, 0.1);
  min-width: 500px;
  width: fit-content;
    
  &::before {
    content: '';
    position: absolute;
    top: -50%;
    left: -50%;
    width: 200%;
    height: 200%;
    background: radial-gradient(circle, var(--color-neon-purple) 0%, transparent 70%);
    opacity: 0.08;
    animation: rotateCode 20s linear infinite;
    pointer-events: none;
  }
  
  @keyframes rotateCode {
    from {
      transform: rotate(0deg);
    }
    to {
      transform: rotate(360deg);
    }
  }
`;

const CodeHeader = styled.div`
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  padding: var(--space-md) var(--space-lg);
  background: var(--color-dark-surface-elevated);
  border-bottom: 1px solid rgba(153, 69, 255, 0.2);
`;

const WindowDot = styled.div`
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background: ${props => props.color};
  opacity: 0.8;
`;

const CodeTitle = styled.span`
  margin-left: var(--space-md);
  color: var(--color-text-secondary);
  font-family: var(--font-mono);
  font-size: var(--text-sm);
`;

const blink = keyframes`
  0%, 49% {
    opacity: 1;
  }
  50%, 100% {
    opacity: 0;
  }
`;

const TypewriterContainer = styled.div`
  position: relative;
`;

const StyledSyntaxHighlighter = styled(SyntaxHighlighter)`
  margin: 0 !important;
  padding: var(--space-xl) !important;
  background: transparent !important;
  font-size: 14px !important;
  line-height: 1.5 !important;
  
  @media (min-width: 1921px) {
    font-size: 16px !important;
  }
  
  @media (max-width: 1280px) {
    font-size: 13px !important;
  }
  
  & code {
    font-family: var(--font-mono) !important;
    font-weight: 400;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    text-rendering: optimizeLegibility;
    white-space: pre !important;
    word-break: normal !important;
    overflow-wrap: normal !important;
  }
  
  /* Custom line highlighting on hover */
  & .token-line:hover {
    background: rgba(153, 69, 255, 0.05);
    position: relative;
  }
`;

const CodeDisplay = () => {
  const [displayedCode, setDisplayedCode] = useState('');
  const [isTypingComplete, setIsTypingComplete] = useState(false);
  const [showCursor, setShowCursor] = useState(true);
  const typingTimeoutRef = useRef(null);
  const currentIndexRef = useRef(0);
  
  const luaCode = `local Developer = {}
Developer.__index = Developer

function Developer:new(name, role, skills, contact)
    return setmetatable({
        name = name,
        role = role,
        skills = skills,
        contact = contact
    }, self)
end

local Kenshin13 = Developer:new(
    "Kenshin13",
    "Backend Developer",
    { "Lua", "JS/TS", "C#", "Java", "PHP", "SQL", "MongoDB" },
    {
        discord = "kenshin13",
        github = "github.com/kenshiin13"
    }
)
`;

  const typeCode = useCallback(() => {
    if (currentIndexRef.current < luaCode.length) {
      const nextChar = luaCode[currentIndexRef.current];
      setDisplayedCode(prev => prev + nextChar);
      currentIndexRef.current++;
      
      // Variable typing speed for more natural effect
      let delay = 22; // Base typing speed (faster)
      
      // Add slight randomness
      delay += Math.random() * 15;
      
      // Pause at certain characters for realism
      if (nextChar === '\n') {
        delay = 70; // Pause at line breaks
      } else if (nextChar === '(' || nextChar === ')' || nextChar === '{' || nextChar === '}') {
        delay = 45; // Slight pause at brackets
      } else if (nextChar === ' ') {
        delay = 15; // Faster for spaces
      }
      
      typingTimeoutRef.current = setTimeout(() => {
        typeCode();
      }, delay);
    } else {
      // Typing complete
      setIsTypingComplete(true);
      // Keep cursor visible for a bit, then hide it
      setTimeout(() => {
        setShowCursor(false);
      }, 2000);
    }
  }, [luaCode.length]);
  
  useEffect(() => {
    // Start typing effect after a short delay
    const startDelay = setTimeout(() => {
      typeCode();
    }, 800);
    
    return () => {
      clearTimeout(startDelay);
      if (typingTimeoutRef.current) {
        clearTimeout(typingTimeoutRef.current);
      }
    };
  }, [typeCode]);

  // Custom style for Lua syntax highlighting - extending vscDarkPlus
  const customStyle = {
    ...vscDarkPlus,
    'pre[class*="language-"]': {
      ...vscDarkPlus['pre[class*="language-"]'],
      background: 'transparent',
      margin: 0,
    },
    'code[class*="language-"]': {
      ...vscDarkPlus['code[class*="language-"]'],
      background: 'transparent',
    },
  };
  
  return (
    <CodeContainer
      initial={{ opacity: 0, rotateY: -15, scale: 0.9 }}
      animate={{ opacity: 1, rotateY: 0, scale: 1 }}
      transition={{ duration: 0.8, delay: 0.3 }}
      whileHover={{ rotateY: 5, scale: 1.02 }}
    >
      <CodeHeader>
        <WindowDot color="#ff5f57" />
        <WindowDot color="#ffbd2e" />
        <WindowDot color="#28ca42" />
        <CodeTitle>server.lua</CodeTitle>
      </CodeHeader>
      
      <TypewriterContainer>
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.5 }}
        >
          <StyledSyntaxHighlighter
            language="lua"
            style={customStyle}
            showLineNumbers
            lineNumberStyle={{ 
              color: '#6e6e80',
              paddingRight: '20px',
              userSelect: 'none',
              minWidth: '45px',
              fontSize: 'inherit',
              fontWeight: '400',
            }}
          >
            {displayedCode + (showCursor && !isTypingComplete ? '█' : '')}
          </StyledSyntaxHighlighter>
        </motion.div>
      </TypewriterContainer>
    </CodeContainer>
  );
};

export default CodeDisplay;