import React, { useRef, useEffect } from 'react';
import styled from 'styled-components';
import { motion, useScroll, useTransform } from 'framer-motion';
import gsap from 'gsap';
import ParticleField from './ParticleField';
import AnimatedTitle from './AnimatedTitle';
import CodeDisplay from './CodeDisplay';

const HeroSection = styled.section`
  min-height: 100vh;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: clip;
  background: radial-gradient(ellipse at top, var(--color-royal-purple) 0%, var(--color-deep-purple) 50%);
  padding: var(--space-4xl) 0;
  
  @media (max-width: 768px) {
    padding: var(--space-3xl) 0;
    min-height: 100svh; /* Use small viewport height for mobile */
  }
  
  @supports (padding: max(0px)) {
    @media (max-width: 768px) {
      padding-top: max(var(--space-3xl), env(safe-area-inset-top));
      padding-bottom: max(var(--space-3xl), env(safe-area-inset-bottom));
    }
  }
`;

const HeroContent = styled.div`
  position: relative;
  z-index: 10;
  width: 100%;
  max-width: 1440px;
  margin: 0 auto;
  padding: 0 var(--space-xl);
  display: grid;
  grid-template-columns: minmax(0, 45fr) minmax(0, 55fr);
  gap: var(--space-5xl);
  align-items: center;
  min-height: 600px;
  
  @media (max-width: 1024px) {
    grid-template-columns: 1fr;
    text-align: center;
    gap: var(--space-3xl);
  }
  
  @media (max-width: 768px) {
    padding: 0 var(--space-lg);
    min-height: auto;
    gap: var(--space-2xl);
  }
  
  @media (max-width: 480px) {
    padding: 0 var(--space-md);
  }
`;

const LeftColumn = styled(motion.div)`
  position: relative;
`;

const RightColumn = styled(motion.div)`
  position: relative;
  overflow: visible;
  @media (max-width: 1024px) {
    display: none;
  }
`;

const Subtitle = styled(motion.p)`
  font-size: var(--text-xl);
  color: var(--color-light-purple);
  margin-bottom: var(--space-lg);
  font-weight: 500;
  letter-spacing: var(--tracking-wide);
  
  @media (max-width: 768px) {
    font-size: var(--text-lg);
    margin-bottom: var(--space-md);
  }
  
  @media (max-width: 480px) {
    font-size: var(--text-base);
  }
`;

const Description = styled(motion.p)`
  font-size: var(--text-lg);
  color: var(--color-text-secondary);
  line-height: var(--leading-relaxed);
  margin-bottom: var(--space-2xl);
  max-width: 600px;
  
  @media (max-width: 1024px) {
    margin: 0 auto var(--space-2xl);
  }
  
  @media (max-width: 768px) {
    font-size: var(--text-base);
    margin-bottom: var(--space-xl);
  }
  
  @media (max-width: 480px) {
    font-size: var(--text-sm);
    line-height: var(--leading-normal);
  }
`;

const CTAContainer = styled(motion.div)`
  display: flex;
  gap: var(--space-lg);
  flex-wrap: wrap;
  
  @media (max-width: 1024px) {
    justify-content: center;
  }
  
  @media (max-width: 480px) {
    flex-direction: column;
    gap: var(--space-md);
    width: 100%;
  }
`;

const CTAButton = styled(motion.a)`
  position: relative;
  padding: var(--space-md) var(--space-2xl);
  font-size: var(--text-base);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: var(--tracking-wider);
  border-radius: var(--radius-full);
  overflow: hidden;
  transition: all var(--duration-normal) var(--ease-out-expo);
  cursor: pointer;
  text-decoration: none;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 44px;
  -webkit-tap-highlight-color: transparent;
  
  @media (max-width: 480px) {
    width: 100%;
    padding: var(--space-md) var(--space-xl);
    font-size: var(--text-sm);
  }
  
  &.primary {
    background: var(--gradient-neon);
    color: var(--color-text-primary);
    box-shadow: var(--shadow-glow);
    
    &:hover {
      box-shadow: var(--shadow-glow-intense);
      transform: translateY(-2px) scale(1.05);
    }
  }
  
  &.secondary {
    background: transparent;
    color: var(--color-neon-purple);
    border: 2px solid var(--color-neon-purple);
    
    &:hover {
      background: var(--color-neon-purple);
      color: var(--color-text-primary);
      border-color: transparent;
      transform: translateY(-2px) scale(1.05);
    }
  }
  
  &::before {
    content: '';
    position: absolute;
    top: 50%;
    left: 50%;
    width: 0;
    height: 0;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.3);
    transform: translate(-50%, -50%);
    transition: width 0.6s, height 0.6s;
  }
  
  &:hover::before {
    width: 300px;
    height: 300px;
  }
`;

const FloatingElement = styled(motion.div)`
  position: absolute;
  width: 300px;
  height: 300px;
  border-radius: 50%;
  background: radial-gradient(circle, var(--color-neon-purple) 0%, transparent 70%);
  filter: blur(60px);
  opacity: 0.3;
  pointer-events: none;
  
  @media (max-width: 768px) {
    width: 200px;
    height: 200px;
    filter: blur(40px);
    opacity: 0.2;
  }
  
  @media (max-width: 480px) {
    display: none; /* Hide on very small screens for performance */
  }
`;

const Hero = () => {
  const sectionRef = useRef(null);
  const { scrollYProgress } = useScroll({
    target: sectionRef,
    offset: ["start start", "end start"]
  });
  
  const y = useTransform(scrollYProgress, [0, 1], [0, -100]);
  const opacity = useTransform(scrollYProgress, [0, 0.8], [1, 0]);
  
  useEffect(() => {
    // Floating animation for background elements
    const floatingElements = document.querySelectorAll('.floating');
    floatingElements.forEach((el, i) => {
      gsap.to(el, {
        y: "random(-30, 30)",
        x: "random(-30, 30)",
        rotation: "random(-15, 15)",
        duration: "random(4, 6)",
        repeat: -1,
        yoyo: true,
        ease: "power1.inOut",
        delay: i * 0.2
      });
    });
  }, []);
  
  const leftColumnVariants = {
    hidden: { opacity: 0, x: -100 },
    visible: {
      opacity: 1,
      x: 0,
      transition: {
        duration: 0.8,
        ease: [0.6, -0.05, 0.01, 0.99],
        staggerChildren: 0.2
      }
    }
  };
  
  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.6 }
    }
  };
  
  return (
    <HeroSection ref={sectionRef}>
      <ParticleField />
      
      {/* Floating background elements */}
      <FloatingElement 
        className="floating"
        style={{ top: '10%', left: '5%' }}
      />
      <FloatingElement 
        className="floating"
        style={{ bottom: '20%', right: '10%' }}
      />
      
      <HeroContent>
        <LeftColumn
          variants={leftColumnVariants}
          initial="hidden"
          animate="visible"
          style={{ y, opacity }}
        >
          <motion.div variants={itemVariants}>
            <Subtitle>Developer / Freelancer / Problem Solver</Subtitle>
          </motion.div>
          
          <AnimatedTitle />
          
          <motion.div variants={itemVariants}>
            <Description>
              Passionate about creating unique roleplay experiences. I help communities bring their server dreams to life.
            </Description>
          </motion.div>
          
          <motion.div variants={itemVariants}>
            <CTAContainer>
              <CTAButton href="#services" className="primary">
                Explore Services
              </CTAButton>
              <CTAButton href="#clients" className="secondary">
                View Clients
              </CTAButton>
            </CTAContainer>
          </motion.div>
        </LeftColumn>
        
        <RightColumn
          initial={{ opacity: 0, scale: 0.8 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ duration: 1, delay: 0.5 }}
        >
          <CodeDisplay />
        </RightColumn>
      </HeroContent>
    </HeroSection>
  );
};

export default Hero;