import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

/**
 * CSS-based native smooth scrolling
 * No lag, no delay - just native browser smoothing with enhanced animations
 */
export const initCSSNativeScroll = () => {
  // Enable CSS smooth scrolling
  document.documentElement.style.scrollBehavior = 'smooth';
  
  // Configure ScrollTrigger for best performance
  ScrollTrigger.config({
    ignoreMobileResize: true,
    autoRefreshEvents: "visibilitychange,DOMContentLoaded,load"
  });
  
  // Enhanced keyboard navigation (optional)
  const handleKeydown = (e) => {
    const scrollAmount = window.innerHeight * 0.9;
    let targetScroll = null;
    
    switch(e.key) {
      case 'ArrowDown':
        targetScroll = window.scrollY + 120;
        break;
      case 'ArrowUp':
        targetScroll = window.scrollY - 120;
        break;
      case 'PageDown':
      case ' ':
        if (!e.shiftKey) {
          targetScroll = window.scrollY + scrollAmount;
          e.preventDefault();
        }
        break;
      case 'PageUp':
        targetScroll = window.scrollY - scrollAmount;
        break;
      case 'Home':
        targetScroll = 0;
        break;
      case 'End':
        targetScroll = document.documentElement.scrollHeight - window.innerHeight;
        break;
      default:
        return;
    }
    
    if (targetScroll !== null) {
      e.preventDefault();
      window.scrollTo({
        top: targetScroll,
        behavior: 'smooth'
      });
    }
  };
  
  // Update ScrollTrigger on scroll (debounced)
  let scrollTimeout;
  const handleScroll = () => {
    clearTimeout(scrollTimeout);
    scrollTimeout = setTimeout(() => {
      ScrollTrigger.update();
    }, 100);
  };
  
  // Add event listeners
  window.addEventListener('keydown', handleKeydown);
  window.addEventListener('scroll', handleScroll, { passive: true });
  
  // Handle resize
  window.addEventListener('resize', () => {
    ScrollTrigger.refresh();
  });
  
  // Initial refresh
  ScrollTrigger.refresh();
  
  // Cleanup function
  return () => {
    document.documentElement.style.scrollBehavior = 'auto';
    window.removeEventListener('keydown', handleKeydown);
    window.removeEventListener('scroll', handleScroll);
    clearTimeout(scrollTimeout);
  };
};